    // .............
    // #1: Start2

    void passage1_Init()
    {
        this.Passages[@"Start2"] = new StoryPassage(@"Start2", new string[] { }, passage1_Main);
    }

    IStoryThread passage1_Main()
    {
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("MY FATHER\'S WORK");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Choose a Scenario for ");
            yield return text(Vars.playtxt);
            yield return text(" ");
            yield return text("players:");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("A Time of War", "Scenario2", null);
        yield return lineBreak();
        yield return link("Industry Forever", "Scenario3", null);
        yield return lineBreak();
        yield return link("Fear and Politics", "ScenarioBox-FOTU", null);
        yield return lineBreak();
        yield return link("The Cost of Disease", "Scenario5Start", null);
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("italic", true))
        {
            yield return text("For an explanation of how to use this Storybook,");
        }
        yield return text(" ");
        yield return link("click here.", "StoryBook", null);
        yield return lineBreak();
        Vars.tracker = 0;
        yield break;
    }


    // .............
    // #2: FearoftheUnknownStart

    void passage2_Init()
    {
        this.Passages[@"FearoftheUnknownStart"] = new StoryPassage(@"FearoftheUnknownStart", new string[] { "INTRO", }, passage2_Main);
    }

    IStoryThread passage2_Main()
    {
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GENERATION I: Fear of the Unknown");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;//macros1.either((HarloweSpread)Vars.randomplayer);
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("14 July, 1831.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("It is with great reticence that I relay a grievous event which occurred upon my a" +
            "rrival. It is my hope that in penning these thoughts my mind will find solace fr" +
            "om the foul images that have so firmly embedded themselves.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I will spare you the details of the journey to that dismal village to settle my deceased father's affairs. But upon entering its unpaved limits, my spouse drew my attention to several men and women galloping towards the town center, where there was a loud commotion and gathering of individuals. Intrigued by the local pageantry, I resolved to indulge my curiosity. I rapped my knuckles against the roof of the carriage and asked for the driver to turn towards the festivities.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"He did not respond to my insistence. Nor did he respond when I thrice repeated my command. Frustrated, I angled my head out of the carriage window in order to speak more firmly. That is when I spied the horrific source of his obstinate and wise decision. For the briefest of moments — though a moment long enough for it to be etched within my memory forever — I saw the source of the commotion: A crowd of people surrounded a tall wooden stage where, swinging slowly from a thick hemp noose, hung a youthful woman. Her lifeless eyes stared in my direction before her form was obscured by buildings.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"An irrational fear has gripped the populace. I swear it. The region is rife with superstitious traditions; traditions that do not mix well with the Church's rigid moral compass. When an individual from this close-knit community emerges from shuttered windows, they eye me as one would a foreigner, with sideways glances that make each excursion there insufferable. Accusations of witchcraft and voodooism erupt with increasing fervor, and paranoia weaves its tendrils into their minds.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Maybe this forced solitude will prove beneficial to my wits, as even amidst this clamor I find myself unnaturally focused. I have recently discovered my father's leather-bound journal and, while somewhat trite, I feel it has sparked something within me; a direction for my future studies, perhaps. Maybe it will offer some amusement in these trying times.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Continue...", "ManiaSpecial", null);
        yield return lineBreak();
        Vars.newspaper = "The " + Vars.townname + " " + macros1.either("Ledger", "Gazette", "Mercury", "Village Voice", "Examiner");
        Vars.whpg = 0;
        Vars.fp10vp = 0;
        Vars.fpresearch2 = 0;
        Vars.fpsanity3 = 0;
        Vars.fpcreepy3 = 0;
        Vars.gen3pg = 0;
        Vars.plA = 0;
        Vars.plB = 0;
        Vars.plC = 0;
        Vars.plD = 0;
        Vars.plE = 0;
        Vars.onecount = 0;
        yield return lineBreak();
        yield break;
    }


