                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text("\'s Journal - ");
            using (styleScope("italic", true))
            {
                yield return text("16 September, 1850. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It is nearing midnight now, and I struggle to find my words. Is this remorse I feel, or elation? Even as I was swept into the midst of the frightened crowd, watching the flames swirl upwards, I was spellbound by their savagery. I could not imagine that this paranoia would be exercised so bluntly!");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("It began over supper with my siblings: ");
        using (styleScope("bold", true))
        {
            yield return text("The Blacksmith");
        }
        yield return text(" ");
        yield return text("- accused of practicing witchcraft - was carried past our brasserie to the steps " +
            "of Town Hall. He wailed and protested his innocence, and when allowed use of his" +
            " hands, he immediately accused Henriette, the town ");
        using (styleScope("bold", true))
        {
            yield return text("Butcher");
        }
        yield return text(", of beguiling him. Within moments, he dramatically convulsed and acted as if und" +
            "er a trance when she decried his accusation.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("As we investigated the commotion that had interrupted our dessert course more clo" +
            "sely, the ");
        using (styleScope("bold", true))
        {
            yield return text("Blacksmith\'s");
        }
        yield return text(" ");
        yield return text("eyes blazed with fiery determination. He pled with us specifically. He would offe" +
            "r us his services, whatever we needed to spare his life.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The ");
        using (styleScope("bold", true))
        {
            yield return text("Butcher");
        }
        yield return text(" ");
        yield return text("was pressed to the steps of Town Hall. Silent, innocent as she approached, and fo" +
            "rlorn. We knew that Henriette would offer the same deal.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("There was no way to slake the public\'s thirst for catharsis without bloodshed. To" +
            "night, a witch was burned.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Click to continue...", "2PS4Kill2", null);
        }
        else
        {
            yield return link("Click to continue...", "S4Kill2", null);
        }
        yield return lineBreak();
        yield break;
    }


