            yield return text(@"For a few years, I watched as the village's hostilities softened and the peasantry returned to their quaint ways of living. But, before long, old rumors of pagan worship and occult manipulations resurfaced. The village has become united in the opinion that the ");
            using (styleScope("bold", true))
            {
                yield return text("public execution of the humble Butcher");
