            yield return lineBreak(); //br tag
            using (styleScope("hook", "h00006"))
                yield return link("Unfortunately, the town became further incensed and searched for an alternative s" +
            "olution.", null, () => enchantHook("h00006", HarloweEnchantCommand.Replace, passage9_Fragment_0));
        }
        //if (Vars.kill == "blacksmith")
        else
        {
            using (styleScope("bold", true))
            {
                yield return text("Paranoia Fades");
