            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" II,");
            yield return lineBreak(); //br tag
            yield return lineBreak(); //br tag
            yield return text("With your return from university imminent, I thought it best to relay to you the " +
            "state of affairs in ");
            yield return text(Vars.townname);
            yield return text(".");
            yield return lineBreak(); //br tag
            yield return lineBreak(); //br tag
            yield return text("For a few years, I watched as the village\'s hostilities softened and the peasantr" +
            "y returned to their quaint ways of living. And as the years continued, the horri" +
            "ble spectacle of ");
            using (styleScope("bold", true))
            {
                yield return text("the Blacksmith\'s execution");
            }
            yield return text(" soon became a strictly taboo subject. Your scientific efforts and somewhat ignobl" +
