            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("April, 1863. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I hope you will forgive the direct manner in which this letter is received. Due to recent events, I no longer entrust my correspondence to postal carriers and prefer to hire discrete private couriers. This message is meant for your eyes only and I will not allow those who so blatantly scheme against me an opportunity to uncover my motives!");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("This town has gone mad.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I have only just been situated these past few months with my spouse and close servants, and scarcely familiarized myself with the thatched-roofs and bucolic scenery, yet already I have seen the fires blaze at night, the screams of the damned, and the gibbet creaking under the weight of swinging bodies. The mob comes with torches in the evening and rips the accused from their residences. It appears that my parent's warnings proved true. The occult hysteria that they endured has returned in earnest! I fear that I may be next!");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Even my own cousins have begun to eye me like mongrel dogs, yearning for scraps. In their jealous mania, they wish to uncover my secrets and claim them for their own. I can see how they desire to place the blame upon me; to distract me from completing my family's important scientific work! It would break my heart to see ill come to them, yet if they continue in their provocations, I will not hesitate to unleash the fires of hell upon them.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("But I am secure in my ambitions. I have uncovered my true purpose. I will not suc" +
            "cumb to fear. My secret work consumes my waking hours and I will stop at nothing" +
            " to see it come to fruition!");
        yield return lineBreak();
        Vars.path4 = "PEForeign";
        yield return lineBreak();
        yield return link("Click to continue...", "CommemorativeIntro", null);
        yield return lineBreak();
        Vars.brickvalue = macros1.either(1, 2);
        if (Vars.kill == "butcher")
        {
            Vars.wsuspect = "Butcher\'s Apprentice";
        }
        else if (Vars.kill == "blacksmith")
        {
            Vars.wsuspect = "Blacksmith\'s Apprentice";
        }
        if (Vars.players == 2)
        {
            Vars.witch = macros1.either(Vars.nameA, Vars.nameB, Vars.nameA, Vars.nameB, Vars.wsuspect);
        }
