    // .............
    // #14: CreatureIntro

    void passage14_Init()
    {
        this.Passages[@"CreatureIntro"] = new StoryPassage(@"CreatureIntro", new string[] { "INTRO", }, passage14_Main);
    }

    IStoryThread passage14_Main()
    {
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GENERATION II: Towards Civility");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            //yield return text(" ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("2 March 1863. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("As mariners are wont to say; there is always a lull before the storm. As I am won" +
            "t to say; a lowering of barometric pressure generally occurs before the storm. A" +
            "nd this idiom certainly applies to the horror of my current situation.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"My family's manor is set on a small precipice, its imposing iron gate emerging from the forest like the mouth of an otherworldly beast. You have no doubt seen the daguerreotype, so I will not delve further into detail. I remembered the daunting architecture from my youth, and returning to claim my inheritance left me feeling trepidatious.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Whatever the cause, it appears the delirium of the past has ebbed and conversations about the darker history of the town are now relegated to whispers in private. The consensus is that justice has been served and modern living has prevailed over the old ways. In fact, there are many who deny that the events occurred at all.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The underlying symptoms of mass hysteria have channeled themselves into other menial and unproductive modes of thinking. I am of the opinion that they overcompensate for the shames of their past. While the ground has just been broken, the district has invested in the most modern alienist philosophies — absurd and untested as those theories are — and a new Asylum is being constructed to focus on the rehabilitation of the mind.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("So, like a wolf licking its wounds, the town has returned to a relative peace. An" +
            "d for a moment, it seemed that the calm would provide a welcome atmosphere to re" +
            "turn to my labors.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("That is, until the Creature appeared in my window one night, it\'s bulky frame wet" +
            " with rain.");
        yield return lineBreak();
        yield return lineBreak();
        Vars.mog = 0;
        Vars.path4 = "PECreature";
        yield return lineBreak();
        yield return link("Continue...", "CreatureDemands", null);
        yield return lineBreak();
        Vars.liber = 0;
        Vars.conse = 0;
        Vars.asupg = macros1.either(1, 2);
        Vars.asylumup = macros1.either("Asylum Labor Union", "Key to the Asylum", "Asylum Share");
        Vars.did1 = macros1.either("Puppy", "Bride", "Puppy and Bride");
        Vars.curecount = 0;
        Vars.bhome = 0;
        Vars.crpg = 0;
        Vars.Acont = 0;
        Vars.Bcont = 0;
        Vars.Ccont = 0;
        Vars.Dcont = 0;
        Vars.Econt = 0;
        yield break;
    }


