    // .............
    // #17: IsolationIntro

    void passage17_Init()
    {
        this.Passages[@"IsolationIntro"] = new StoryPassage(@"IsolationIntro", new string[] { "INTRO", }, passage17_Main);
    }

    IStoryThread passage17_Main()
    {
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GENERATION III: Isolation and Ignorance");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("30 March, 1892. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I tell you, these damn peasants actually built a wall around their own town. In t" +
            "he 1800\'s no less! These fools have traded paranoia for utter delusion!");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Do they expect a foreign government to set up a military line and trebuchets to lay siege to this backwater stronghold? What on earth would it offer them? Trade has suffered. Prices have risen. And most importantly, with the caravans left to go elsewhere, I must find alternative ways to procure knowledge.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Why just this week, I was enraged by the audacity of the intrusion into my affairs! I, the rightful heir to a considerable estate, was forced to suffer the indignity of a physical inspection at what appeared to be a freshly fashioned gateway to the village where I was born. And then, to infer that I was bound by duty to prove my citizenship? My spouse was so manhandled that they were forced to spend the next week in their bedroom consumed by anxious thoughts.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Curse this infernal world filled with frustrations and complications at every turn! If only these regressive tendencies toward isolationism could have been resolved in another way! Surely, you can determine how dire the situation has become if it has rattled my notoriously pragmatic disposition. How can one change the world when it so decidedly wants to remain the same?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Mark my words, I would sooner watch these ramparts crumble than allow them to des" +
            "troy my spirit. I will find a way to circumvent this oppressive state and preser" +
            "ve my legacy at all costs!");
        yield return lineBreak();
        Vars.path4 = "PEIsolation";
        Vars.visit = 1;
        yield return lineBreak();
        yield return link("Click to continue...", "IsoBricksRes", null);
        yield return lineBreak();
        if (Vars.townname == "debug")
        {
            yield return text("v1.0");
        }
        yield break;
    }


    // .............
    // #18: TensionIntro

