    IStoryThread passage18_Main()
    {
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GENERATION III: Old Habits");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal of ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("April 1892.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Ah, what relief it is for one to not spend each waking moment fearing they will be burned at the stake! The oppressive hostilities of the Romanian countryside, of which I had become familiar during my youth, made the anxiety of my carriage-bound return to the old estate a dreadful prospect.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Yet, even as the ink dried upon the executor's paperwork, my spouse and I quietly enjoyed our coffee against the bustle of a cobblestone street. The only eyes upon us were those clearly impressed by our bright, Parisian attire. Never once did an errant gaze suggest I would be shot with a revolver or murdered viciously by a stiletto. It was almost disappointing.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"With the town's decision to forgo construction of a barrier, the emergence of additional trade and the ceasing of xenophobic hostilities has allowed further interaction with other cultures. I find myself entertaining exotic guests that pique my darker interests. The occult and its superstitious effects on my family's past has become a peculiar fascination. Spiritualism being the fashion these days, you know.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"However, ""old habits die hard"" as the saying goes, and a delicious tension roils beneath the surface of the town. Acceptance (or apathy) may have calmed the tempest of hatred, but I realize that this deep psychological infection has yet to be fully reconciled. With each visit, I feel my actions push these factions closer until they will be forced to make a potentially devastating and amusing decision.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("It is an experiment in itself; a powder keg waiting to go off. And I am desperate" +
            " to observe the results.");
        yield return lineBreak();
        Vars.path4 = "PETension";
        Vars.visit = 2;
        Vars.tensegood = 0;
        Vars.tensebad = 0;
        Vars.ten = 0;
        Vars.eor = 0;
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "TensionSetting", null);
        yield return lineBreak();
        if (Vars.townname == "debug")
        {
            yield return text("v1.0");
        }
        yield break;
    }


