    // #23: PrivatizedIntro

    void passage23_Init()
    {
        this.Passages[@"PrivatizedIntro"] = new StoryPassage(@"PrivatizedIntro", new string[] { "INTRO", }, passage23_Main);
    }

    IStoryThread passage23_Main()
    {
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GENERATION III: Conducting Business");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("9 February, 1892. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I will keep this letter brief — as brief as I can. You are aware that brevity is not my strongest suit. However, it is August, the ink struggles to dry in the humidity, and my mind is set on complicated things. Perhaps it would be more amiable to pen this missive in my own blood, cold as I am perceived to be by the inhabitants of this gray, lifeless city. It would certainly bring a little more color to it.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"You are probably interested in matters of business, and it is going exceedingly well, or so I hear — I struggle to keep the figures in my head. I, and regrettably my good cousins, whom I love dearly, have invested directly in the town's well-being and now own a substantial portion of the commercial district. It appears that my parent's investments have paid off handsomely.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"News of the day: The Asylum Project, which I believe was misguided from the beginning, has become a more intriguing source of labor. It's not that I believe that rehabilitation of the deviant mindset is impossible, it simply requires a more aggressive therapy than they were willing to indulge. With our unmediated assistance and the endorsement of the state, a prison is a more versatile testing ground.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"And I — I am doing well. It disconcerts me. My studies continue with great passion that consumes me more than anything I have ever known. Even the dismal fog that looms across this bleak valley fills me with a solemn peace. Yet it is that same calm which causes my unease.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I must work quickly, as I feel something unseen watches, waiting to emerge from t" +
            "he shadows. I cannot have destiny torn from my grasp just when I reach the pinna" +
            "cle!");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "PrivatetoJail", null);
        yield return lineBreak();
        Vars.exped = 0;
        Vars.hunt = 0;
        Vars.path4 = "PEPrivatized";
        if (Vars.townname == "debug")
        {
            yield return text("v1.0");
        }
        if (Vars.kill == "butcher")
        {
            Vars.warden = "The Butcher";
        }
        //if (Vars.kill == "blacksmith")
        else
        {
            Vars.warden = "The Bloodsmith";
        }
        Vars.junkpenalty = macros1.either("Lose 5VP", "Discard a Vanity Estate Upgrade from your Estate if possible.");
        Vars.creepcount = 0;
        yield return lineBreak();
        yield break;
    }


    // .............
    // #24: LiberalIntro

