    }

    IStoryThread passage24_Main()
    {
        //yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("GENERATION III: Acceptance");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            //Vars.randomname = macros1.either((HarloweSpread)Vars.randomplayer);
            if (Vars.players == 2)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
            }
            if (Vars.players == 3)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
            }
            if (Vars.players == 4)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
            }
            if (Vars.players == 5)
            {
                Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
            }
            Vars.randomname = Vars.randomplayer;
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("9 February, 1892. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I apologize for the tardiness of my reply, but settling the matters of my inheritance has uncovered distressing revelations that haunt my waking hours. It is terrible. And by terrible, I mean decent, cheerful, and painfully dull. People stroll around this inviting town, greet each other with smiles, and share baked goods. Baked goods! How are they so blind to the dark realities of the world? How did we arrive at such an excruciatingly positive conclusion?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"While other institutions across Europe experienced the ravenous strain of overcrowding, our town’s well-funded lunatic asylum proved a luminous model of rehabilitation. Restraints were traded for personal care from the staff and a work release program was expanded for patients eager to assimilate themselves into society once again, with the skills to succeed.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It is an interesting concept in theory, but one which we know will only end in folly. When I made a brief visit to the Asylum Program (as they now so boldly call it), they even attempted to evaluate me as if I had been admitted. Apparently, the country has turned to more civilized ways to disenfranchise individuals that they fear — not to mention the additional taxes levied against legitimate entrepreneurs such as myself.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Like mighty Atlas, I will accept these heavy charges. While I disagree with their methodology, and the expenses of this progressive approach will certainly be a financial burden, access to skilled labor does appeal to me from an efficiency standpoint, if they have the stomach for it.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The days are certainly bright here in the valley, but in the end, this light will" +
            " only make my family\'s work shine more brilliantly!");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "LiberalHomeTile", null);
        yield return lineBreak();
        Vars.exped = 0;
        Vars.path4 = "PELiberal";
        Vars.asylumcount = 0;
        Vars.gen3pg = 0;
        if (Vars.townname == "debug")
        {
            yield return text("v1.0");
        }
        yield break;
    }


