    {
        this.Passages[@"CreatureDemands"] = new StoryPassage(@"CreatureDemands", new string[] { "INTRO", }, passage46_Main);
    }

    IStoryThread passage46_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("The Creature\'s Demands");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(Cont.)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"To my surprise, the hideous monster could speak, his jaw supported by a crudely stitched black thread which exposed the inner muscle when it moved. In deep, guttural tones, he conveyed his hatred for my grandfather, who had created him and abandoned him, helpless in the wild. ""I was forcefully orphaned. Left to fend for myself while his sons and daughters existed in luxury,"" he groaned.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"They say the sins of the father are passed on to the children, but rarely does this obligation skip a full generation. ""You owe me a great debt, and I am here to demand payment,"" he stated firmly, and obstructed my escape until he could finish his tale. I was awestruck by his chilling words and the revelation that our family's dark secrets were indeed a reality.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Cursed into existence despite his decaying form, my grandfather's experiment demanded to live out his days with a faithful companion, another being who can understand the torture of existence. That it was my family's duty to atone for these sins and create it for him!");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("With a final turn, his grotesque figure framed in moonlight, he vowed that if we " +
            "did not, he would exact a terrible vengeance upon our houses, so that we may kno" +
            "w first-hand what torment he has endured!");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "TheCreatureCard", null);
        yield return lineBreak();
        yield break;
    }


