            yield return text("Journal of ");
            using (styleScope("italic", true))
            {
                yield return text("name illegible");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Success. Oh, if words could adequately describe the crestfallen look on the monstrosity's distorted face as it realized its life was at an end! My servants and I subdued the foul Creature, binding it with rope around its wrists and legs and suspending it upon a felled birch tree with little struggle.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Kindled with underbrush and pine needles, I watched as the smoke turned to flame and slowly consumed the monster. First, the frostbitten feet and legs clad in tattered cloth, then the rusted belt-buckle searing through flesh as it fell red-hot into the fire.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It did not scream as it expired, nor did it writhe in agony, as if the pain of its own existence had already overwhelmed all possible sensation. It merely stared in my direction with a forlorn look in its eyes, like all the world had foresaken it. I could not bear the sight. I raised my pistol and shot it dead.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Click to continue...", passage52_Fragment_5);
        using (styleScope("hook", "h000052"))
            yield return link("Click to continue...", null, () => enchantHook("h000052", HarloweEnchantCommand.Replace, passage52_Fragment_4));
        yield return lineBreak();
        yield break;
    }

