    IStoryThread passage54_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Economic Stimulus");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"As I predicted, the Romanian government's expanding social programs have left it unmercifully poor during this brief recession. I have made protective strides to divert my portfolio abroad, so the impact has been negligible. However, the upheaval caused by this Great War has sparked nationalist sentiments and minor rebellions across Transylvania.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The sudden mantra to protect our own has devolved into a battle within the govern" +
            "ment. I yawn when I dwell on parliamentary matters for too long. I\'m sure it is " +
            "some endless babble about race, human rights, and religious faith.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The result of this prejudice is that now Transylvania is faced with a dreary deci" +
            "sion that has no positive outcome. As landowners and entrepreneurs, naturally, w" +
            "e will make this decision as to how the regional government will proceed.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            yield return link("Click to continue...", "2PLiberalEvent", null);
        }
        else
        {
            yield return link("Click to continue...", "LiberalEvent1", null);
        }
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


