        yield return text(@"My Father's Work is a game of Victorian era mad scientist ambition told over three Generations. The Storybook App controls the direction of the Town depending on the decisions made by players. It will require that players interact with it by clicking on specific passages at certain times.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("End of Round");
        }
        yield return lineBreak();
        yield return text("There are three rounds in each Generation. At the end of each round, you ");
        using (styleScope("bold", true))
        {
            yield return text("must");
        }
        yield return text(" ");
        yield return text("click the bottom link to resolve any special events and move play to the next rou" +
            "nd. The screen will then display the current round and changes to gameplay (if a" +
            "ny).");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
