            " has been performed. This may be taking an action in the Town, your Estate, or c" +
            "ompleting a specific goal. Be sure to click these links to receive a special sto" +
            "ry passage.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to return...", "Start2", null);
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


