    // .............
    // #70: Witchwolfresolution

    void passage70_Init()
    {
        this.Passages[@"Witchwolfresolution"] = new StoryPassage(@"Witchwolfresolution", new string[] { }, passage70_Main);
    }

    IStoryThread passage70_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Accusations");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Word travels quickly in these parts. For as distant I am from the civilized world" +
            ", I am equidistant from any meaningful activity to gossip about. While I\'m sure " +
            "you have heard of the recent family tragedy, I wanted you to read it from my own" +
            " words.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"As cousins, we frequently sup together when time and weather allows. But woefully, one occasion we chose a night where the wind howled remorselessly and set the locust trees to rapping against the estate windows. Upon this uneasy evening, we spied a great light beaming from the forest, and soon a throng of townspeople rallied around the exterior walls, waving torches and brandishing pitchforks.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The townspeople blamed us for bringing a blight of witchcraft upon their town. Tonight, they demanded a sacrifice and no amount of persuasion would slake their thirst for blood. As the hounds kept them at bay, we were forced to make a sanguine decision that would haunt us for the remainder of our days.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "Witchres", null);
        yield return lineBreak();
        yield return lineBreak();
        yield break;
    }


