    IStoryThread passage71_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Memorial to the Past for the Future");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return passage("letter1a");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"As expected - and as I've relayed to you so amusingly in the past - the town is not seeing adequate support for their memorial. This time, however, I was distinctly unamused to have my experimentations interrupted just as I had secured a moment's peace. Only yesterday, well-dressed representatives from the local government (mind you, as well-dressed as a fop with a decade's old sense of fashion can be) visited the estate in person to ask for my assistance.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"When I pressed as to the actual purpose of our donations, they act as a parakeet with its cage door rattled; wildly gesticulating and talking vaguely about eliminating all possible superstition and influence from the town to make it prosperous again. Quite unlikely, I would say.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("My dealings with the local Romani merchants have made it clear that whatever the " +
            "town\'s petty inclinations, the memorial will have a deep affect on their trade. " +
            "The Romani do not wish to leave the region, but will do so if pressed.");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "WallEvent1", null);
        yield return lineBreak();
        yield break;
    }


