        yield return lineBreak();
        if (Vars.randomname == Vars.witch)
        {
            yield return text(@"It was I who was chosen. Harboring no ill will towards my cousins, I bravely faced death and was granted a minor reprieve by the mob to attend to my final affairs, which is how I am able to pen this missive to you in my final days. The stories to the contrary that describe me weeping hysterically and begging are pure fabrication.");
            yield return lineBreak(); //br tag
            yield return lineBreak(); //br tag
            yield return text("I would never harm anyone and I would never use this peculiar circumstance to fur" +
            "ther complicate affairs for my cousins.");
        }
        else if (Vars.wsuspect == Vars.witch)
        {
            yield return text("The town was appeased by our wise decision to sacrifice the true culprit in this " +
            "macabre, mystical mystery. Let it be known that seeking vengeance can carry with" +
            " it a terrible and fatal cost.");
            yield return lineBreak();
            yield return lineBreak();
            yield return text("I only wish the wretch would have taken it better when they were found out. Poor," +
            " ");
            yield return text(Vars.witch);
            yield return text(", spat at us and made a frightfully unbecoming scene while being burnt at the sta" +
            "ke. Ghastly manners.");
        }
        else
        {
            yield return text("The town was appeased by our decision to forgo familial obligations and offer one" +
            " of our own as a necessary sacrifice. I do not know how to state it other than w" +
            "ith sober words. To lose a family member, oh it is a torment to my very soul.");
            yield return lineBreak(); //br tag
            yield return lineBreak(); //br tag
            yield return text("I only wish they would have taken it better. Poor, ");
            yield return text(Vars.witch);
            yield return text(", spat at us and made a frightfully unbecoming scene while being burnt at the sta" +
            "ke.");
