            using (styleScope("italic", true))
            {
                yield return text("14 July, 1831.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The cold and dark landscape should by all accounts be an affront to my demeanor - and it certainly is to my spouse - but I find myself rejuvenated in a way that beguiles my rational mind. They say that ashes can enrich the soil and make the next harvest stronger. Well, if the grayness of this countryside serves as an ample fertilizer, my mind is a germinating seed ready to burst from the Earth.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("This collective mania - it is contagious. Each day I find my mind wandering, drea" +
            "ming up new formulas and calculations, drafting notes as if possessed by some un" +
            "seen force. For now, I will let my thoughts go wherever they are wont to go.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("However, I will find my true calling. In this frenzied era of wild ideas and ince" +
            "ndiary superstitions, I will emerge focused and determined!");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h0000139"))
            yield return link("Click to continue...", null, () => enchantHook("h0000139", HarloweEnchantCommand.Replace, passage139_Fragment_0));


        //yield return link("Click to continue...","Mania",null);
