    // .............
    // #174: JailEvent1

    void passage174_Init()
    {
        this.Passages[@"JailEvent1"] = new StoryPassage(@"JailEvent1", new string[] { }, passage174_Main);
    }

    IStoryThread passage174_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("The Escape");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("(Cont.)");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I met with their leader just days previous, through coercive means I assure you. " +
            "There I was, forced to mingle with criminals and rust-covered sociopaths in cove" +
            "ralls, bruised and thrust upon the steps of the prison, or what they now call th" +
            "e Junk Palace.");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.kill == "blacksmith")
        {
            yield return text(@"A man stepped forward to the cheers of a throng of miscreants. The man was strong and rough with a ruddy complexion, a broad, square jaw, and a beard separated by deep scars along his cheeks. He wore a thick apron with one shoulder strap ripped at the seams. The front was covered in dark stains, and by his confident stride, he seemed to revel in its uncleanliness. In his gloved hand, he held a hammer which dripped with a red substance that also stained his fingers.");
        }
        //if (Vars.kill == "butcher")
        else
        {
            yield return text(@"A woman stepped forward to the cheers of a throng of miscreants. Her hair was cropped shorter than a bob, dark and wild with a sheen of oil. It framed her angular face and draped over a black eye-patch that covered her left eye. She wore a thick apron that was once white, but now stained a dark crimson with fresh droplets of red bespattered across the chest. In her gloved hand, she held a metal cleaver, rusted near the handle, with thick divots in the blade from years of use.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("\"They call me ");
        yield return text(Vars.warden);
        yield return text(". Perhaps you remember my family, and how they were ruined by the accusations of " +
            "hysterical peons so many generations ago. Well now, us unfortunate wretches have" +
            " taken back what is rightfully ours. ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("runs this town.\"");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The aberrant horde roared their approval. The malcontented rabble beat their ches" +
            "ts and clattered metal upon metal. ");
        if (Vars.creature == 1)
        {
            if (Vars.exped == 0)
            {
                yield return text("I spied a shadowy figure within the Junk Palace, its distorted silhouette framed " +
            "against the entryway for a moment before disappearing once again. Was this the s" +
            "ame creature I had hunted for?");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("\"I have brought you here because you are useful. But mark my words, ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("expects loyalty.\"");
        yield return lineBreak();
        yield return lineBreak();
        yield return link("Click to continue...", "JailEvent1A", null);
        yield return lineBreak();
        yield break;
    }


