    // .............
    // #182: Prologue-FOTU

    void passage182_Init()
    {
        this.Passages[@"Prologue-FOTU"] = new StoryPassage(@"Prologue-FOTU", new string[] { }, passage182_Main);
    }

    IStoryThread passage182_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("A Note for my Sister");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Roderick Tenderson - ");
            using (styleScope("italic", true))
            {
                yield return text("1932.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I have made much progress in my research over these last months. My host has furnished me with appropriate accommodations and the food is hearty with a warmth that lifts the spirits. While I am gracious for their hospitality, I have yet to give my appreciation in person. The caretaker assures me that they are on extended holiday, but their absence is peculiar. Something about this arrangement unnerves me, though I cannot for the life of me determine its source.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It is but a minor xenophobia, a fear of the unknown that sets my eyes to dwelling on the dark corners of this unfamiliar, decaying, but immaculate estate. At night, I perceive to hear the echoes of a distant hammering, the scraping of metal on metal, the rumble of thunder. Yet when I sash my nightgown tight and emerge upon the veranda, the misty countryside is spread wide under the moon and I am greeted with nothing but the echo of cicadas and the smell of tulips in the night air.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The business at hand: Included within the accompanying package is an extensive collection of clippings, journal entries, and letters chronicling the storied history of this peculiar estate and its proprietors. Their contents are fascinating and I have arranged them in a semblance of order which tells a vivid, extraordinary tale.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I expect to return to London shortly, but I have posted this ahead of my arrival so as to make the burden lighter for me. I fear I don't have the same fortitude that I once did. If perchance something were to happen to me, I trust you will ensure its publication in whatever form you see fit.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("As always, I think of you fondly. Give mother my warmest regards.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Roderick");
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.players == 2)
        {
            Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB);
        }
        if (Vars.players == 3)
        {
            Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC);
        }
        if (Vars.players == 4)
        {
            Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD);
        }
        if (Vars.players == 5)
        {
            Vars.randomplayer = macros1.either(Vars.nameA, Vars.nameB, Vars.nameC, Vars.nameD, Vars.nameE);
        }
        yield return link("Click to continue...", "FearoftheUnknownStart", null);
        yield return lineBreak();
        yield break;
    }


