        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Cure No.");
        yield return lineBreak();
        yield return text("\"Perhaps it is for the best. \"");
        yield return lineBreak();
        yield return text("(Count appears in the next Generation.)");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
