    // .............
    // #209: FOTU-End1

    void passage209_Init()
    {
        this.Passages[@"FOTU-End1"] = new StoryPassage(@"FOTU-End1", new string[] { }, passage209_Main);
    }

    IStoryThread passage209_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Faded Into Obscurity");
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Correspondence - ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("25 June, 1926");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It feels like ages since I have written. The village that we once sojourned to all those years ago has fallen silent. It's crumbling defenses are a reminder; a metaphor for the crippling isolation of xenophobia. Even now I remember those accursed city walls that sapped my youthful vitality with every visit into the murky depths of that place; a place that could never be rebuilt after the hideous Experiment was unleashed.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"Yet, even now the indomitable pull of my family's infamous work tears at my very soul! No. I cannot carry on a legacy of fear that left an entire town and estate in ruins. My colleagues at the university have no reverence for me. They laugh so heartily when I tell them the town in which I was birthed. I do not blame them. My hope is that I shall never see that foul place again. How could my family cultivate such an embarrassing line of thinking?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("As I pen this note, my lawyer has made arrangements for a transfer of ownership; " +
            "the deed to that wretched estate will soon finally be wrested from my hands and " +
            "with it, the insidious efforts contained within will be buried forever.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield return lineBreak();
        yield break;
    }


    // .............
    // #210: FOTU-End2

    void passage210_Init()
    {
        this.Passages[@"FOTU-End2"] = new StoryPassage(@"FOTU-End2", new string[] { }, passage210_Main);
    }

    IStoryThread passage210_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("A Model City");
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal Entry: ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("1 March, 1924.");
            }
            yield return text(" ");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I see now how wrong I had been. True inspiration, true science, true art, it emerges from isolation. Isolation is the catalyst. With silence and contemplation, the ability to truly focus without distractions, this is where perfection and enlightenment is achieved.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The citizens of ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text("were right in their decision. Outside influences only pollute the mind and distra" +
            "ct.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("One must be self-reliant and self-motivated. Science is instinctual. Brilliance d" +
            "oesn\'t come from universities. No one was ever remembered as the world\'s greates" +
            "t team player. No.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The rest of the world may be unaware of my family\'s work, but that is all part of" +
            " my ingenious plan. Today, I retreat to my laboratory. Soon, I will emerge from " +
            "my scientific cocoon more brilliant than ever before and the world will tremble " +
            "at my feet!");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield return lineBreak();
        yield break;
    }


