            yield return lineBreak();
            yield return passage("letter1a");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"The relapse of paranoid delusion in the rural populace has made life particularly anxious for those who express a scientific aptitude. However, considering that the region's continued hysteria keeps most inhabitants locked within their ashen homes at night, fearful of every shadow that flits across the windowsill, I am reasonably sure that my new obsessions will blend into the macabre scenery unnoticed.");
