        yield return lineBreak();
        yield return lineBreak();
        if (Vars.nameA == Vars.fate1)
        {
            yield return text(@"My lust for fame knows no boundaries. Whether fulfilled through ethical means or the mark of infamy, I was born with a yearning to be known both far and wide for my scientific exploits. These narcissistic thoughts plague my waking hours and infect my dreams!");
            yield return lineBreak();
            yield return lineBreak();

        }
        else if (Vars.nameA == Vars.fate2)
        {
            yield return text("My thirst for knowledge is unquenchable. Each evening I search through ancient to" +
