    IStoryThread passage263_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Taking Charge");
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            if (Vars.curecount == "yes")
            {
                yield return text("Vlad III Dracula");
            }
            else
            {
                yield return text(Vars.winner);
            }
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("12 November, 1924.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("It is my hope that this letter finds you well. The news I hear from Bucharest is " +
            "positive, with a seasonable chill in the air and continued peace. As such, I pra" +
            "y you will indulge me in forgoing pleasantries and moving to matters of business" +
            " with haste.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The institution in ");
        yield return text(Vars.townname);
        yield return text(" ");
        yield return text(@"has been an unrivaled success. A steady stream of those suffering from insanities and delusions have been shipped here from other parts of the country. Yet still officials always wonder how we run such an efficient operation even as funding remains remarkably low. I believe it is in part due to the ");
        using (styleScope("bold", true))
        {
            yield return text(Vars.menname);
            yield return text(" ");
            yield return text("Program");
        }
        yield return text(" ");
        yield return text("which has gained notoriety across Europe for its aggressive tactics. Those involv" +
            "ed in the studies have shown a tremendous improvement in behavior.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Which is why I must repeat my strong request from my previous letter: we require " +
            "more fresh patients to treat. Our near one hundred percent release rate has left" +
            " several vacancies in the facility and we are in dire need to obtain more.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The concerns you expressed in your last letter are valid. What is the status of the released patients? How are we tracking their progress in society? How do you know we haven't simply been failing to treat them and then disposing of their bodies? Why are there bloodstains on the envelope of my previous letter? These are all important questions.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("But, I ask you now; why question ");
        using (styleScope("bold", true))
        {
            yield return text("results");
        }
        yield return text("?");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield break;
    }


