    void passage270_Init()
    {
        this.Passages[@"LiberalReplace"] = new StoryPassage(@"LiberalReplace", new string[] { }, passage270_Main);
    }

    IStoryThread passage270_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Understanding and Support");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            yield return text(Vars.randomname);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("19 May, 1892. Romania.");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The town\'s evolution has been a linear one towards relative peace, and this is in" +
            " part due to the peace of mind that a mental health institute provides.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The Asylum has expanded not only their facilities, but their influence over the h" +
            "earts and minds of the townsfolk. The former being not very difficult to do, I s" +
            "hould say. However, it appears to be in good standing. ");
        if (Vars.jail == 2)
        {
            yield return text("I believe a Dr. Vlad Dracula has taken over as the head of the Asylum Program. I " +
            "have heard positive things about him.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"They have even embraced this idea of rehabilitation so fully that they are willing to send anyone for a general checkup when needed. I'm sure our phrenological colleagues might have a laugh at that one. But it is nice to know that the repercussions for pushing the envelope will be less severe.");
        yield return lineBreak();
        yield return lineBreak();
        //yield return enchantIntoLink("Click to continue...", passage270_Fragment_1);
        using (styleScope("hook", "h000270"))
            yield return link("Click to continue...", null, () => enchantHook("h000270", HarloweEnchantCommand.Replace, passage270_Fragment_0));
        yield return lineBreak();
        yield break;
    }

