    // .............
    // #276: FOTU-End5

    void passage276_Init()
    {
        this.Passages[@"FOTU-End5"] = new StoryPassage(@"FOTU-End5", new string[] { }, passage276_Main);
    }

    IStoryThread passage276_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Peace in Defiance");
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Journal Entry - ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- 16 August, 1929");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Sunday: I had the glorious dream again - it never fails to reinvigorate me, as I " +
            "could relive that moment each night for the remainder of my years and be content" +
            ".");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I watch with steady eyes as my family\'s creation, ");
        if (Vars.winner == Vars.nameA)
        {
            string s = Vars.warriorA.ToString();
            yield return text(s.Replace("_1", ""));
            //yield return text(Vars.warriorA);
        }
        else if (Vars.winner == Vars.nameB)
        {
            string sb = Vars.warriorB.ToString();
            yield return text(sb.Replace("_2", ""));
            //yield return text(Vars.warriorB);
        }
        else if (Vars.winner == Vars.nameC)
        {
            string sc = Vars.warriorC.ToString();
            yield return text(sc.Replace("_3", ""));
            //yield return text(Vars.warriorC);
        }
        else if (Vars.winner == Vars.nameD)
        {
            string sd = Vars.warriorD.ToString();
            yield return text(sd.Replace("_4", ""));
            //yield return text(Vars.warriorD);
        }
        else if (Vars.winner == Vars.nameE)
        {
            string se = Vars.warriorE.ToString();
            yield return text(se.Replace("_5", ""));
            //yield return text(Vars.warriorE);
        }
        else
        {
            string s = Vars.warriorA.ToString();
            yield return text(s.Replace("_1", ""));
            //yield return text(Vars.warriorA);
        }
        yield return text(", with cathartic ambivalence, lifts the severed head of ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text(@"high into the air. I feel the searing heat of burning oil, hear the hiss of rising steam and smoke, and smell the rusted iron in the air. The crowded arena cheered even as their leader was torn from his makeshift throne and tossed lifeless to the dusty Earth, blood pooling beneath, dark and thick as motor oil.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"These images appear in my mind like light on silver even as my weathered hands strain to grasp the quill. My last act of defiance, perhaps. But what is the worth of toppling a regional tyrant? All this effort to shake the world, and barely one square kilometer has been rattled.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("The inmates have moved on. The town is an empty, ruined field without vegetation;" +
            " a decaying pile of ash, rust, and mud. Some days my mind feels the same. The se" +
            "nse of peace does nothing to stem this emptiness of purpose inside of me. ");
        if (Vars.creature == 2)
        {
            yield return text("An old man visits now and then; a friend of the family with a withered face that " +
            "he keeps wrapped tightly with a scarf.");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("What a waste contentment is! What a terrible investment! I only hope my progeny w" +
            "ill leave this broken land behind and forge a new path.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield return lineBreak();
        yield break;
    }


    // .............
    // #277: FOTU-End6

    void passage277_Init()
    {
        this.Passages[@"FOTU-End6"] = new StoryPassage(@"FOTU-End6", new string[] { }, passage277_Main);
    }

    IStoryThread passage277_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text(Vars.warden);
            yield return text(" ");
            yield return text("Forever");
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- 5 May, 1925");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The customs of Transylvania are even stranger than I remember. I had vague recollections from my youth of being schooled in our home and shielded from the smoky village residing deep in that valley, but I could not have guessed the true reasoning behind it all.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("I have forged an alliance with the local government based on my parent\'s good wil" +
            "l. They have democratically elected ");
        yield return text(Vars.warden);
        yield return text(" ");
        yield return text("and have even offered to provide materials and assistance for my continued experi" +
            "mentations. I would understand your initial apprehension at the moniker of ");
        yield return text(Vars.warden);
        yield return text(", but I assure you that the title is derived from a regional dialect and is part " +
            "of tradition. They have even fashioned a gaming arena of sorts within the town p" +
            "roper, where a particularly aggressive form of sparring is practiced.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"In fact, I find this region to be surprisingly inclusive and accepting of the avant-garde, which suits my needs as you might expect. I have even scheduled a meeting this weekend with a local Count. He claims to have been a friend of the family and has resumed interest in business ventures within the district.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield return lineBreak();
        yield break;
    }


    // .............
    // #278: FOTU-End3

    void passage278_Init()
    {
        this.Passages[@"FOTU-End3"] = new StoryPassage(@"FOTU-End3", new string[] { }, passage278_Main);
    }

    IStoryThread passage278_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Springtime for ");
            yield return text(Vars.townname);
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Correspondence from ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("14 June, 1925");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"If you can smell the scent of tea and rich pastries on this paper before you, it is because I write this letter to you from one of my favorite shops along the main street. The shuffling footsteps and metal din of automobiles along concrete allows my thoughts to wander. I find it disagreeably bright in these parts nowadays, but at least they serve a damn fine cuppa. There are definite benefits to traveling merchants offering a steady supply of fine goods.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It appears we have emerged from the dismal environs of yesteryear into a full springtime bloom. My family may have made a few missteps, but it seems their kind-hearted souls (of which I was not aware) won the day and assuaged the fears of the populace. I will say that it is rather enjoyable to sketch out new scientific diagrams in broad daylight without scrutiny.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"There are even some willing to volunteer their time towards my ""eccentric hobbies"" as they call them. Such insufferable fools. I will take pleasure in exploiting their ignorance. But, I will try to be sensible about it - it is unseasonable weather for painful howling.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Anyway, send my best wishes to your mother and do not tarry too long.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Yours Always,");
        yield return lineBreak();
        yield return text(Vars.winner);
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield return lineBreak();
        yield break;
    }


    // .............
    // #279: FOTU-End4

    void passage279_Init()
    {
        this.Passages[@"FOTU-End4"] = new StoryPassage(@"FOTU-End4", new string[] { }, passage279_Main);
    }

    IStoryThread passage279_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("The Anger of the Mob");
        }
        ViewGenerationEnding.instance.EnableDisableContinueBtn(true);
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            yield return text(Vars.winner);
            yield return text(" ");
            yield return text("- ");
            using (styleScope("italic", true))
            {
                yield return text("4 January, 1924");
            }
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"It finally happened. They destroyed it all. Mobs with actual torches and pitchforks, I tell you, knocked down my properly erected fencing and stormed the estate, destroying my parents' work. The curs had the audacity to arrive unannounced; had I not heard the hounds eviscerating several members of the crowd, I may not have escaped before being swallowed up by the flames.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"The grounds still remain fallow and singed by ash, enveloping the plot in a vast, dreary grayness. My entreaties to the governor have been met with indifference and ridicule. It is clear that I will receive no financial remuneration for this riotous behavior. Am I to be forever punished for the sins of my father?");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("No matter! What do they know of loss? I have lost everything. My family\'s legacy " +
            "is in tatters. They drive us away as if we are the outsiders, like foreign begga" +
            "rs.");
        yield return lineBreak();
        yield return lineBreak();
        yield return text("This is not over. I will have vengeance. This paltry village will rue the day it " +
            "crossed, ");
        yield return text(Vars.winner);
        yield return text(", the Fourth!");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("Also, if you would be so kind as to furnish me a small loan, it would certainly e" +
            "xpedite my ability to obtain said revenge.");
        yield return lineBreak();
        yield return lineBreak();
        yield return lineBreak();
        yield return text("THE END?");
        yield return lineBreak();
        yield break;
    }


