    }

    IStoryThread passage284_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("A Life Forsaken");
        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("Letter from ");
            yield return text(Vars.tempid);
            yield return text(" ");
            yield return text("- <i>");
            yield return passage("date1a");
            yield return text("</i>");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text(macros1.either("There was no one there to greet me on that day. As seemed fitting, for this was n" +
            "ot some achievement to be unlocked - it was a personal decision that had long to" +
            "re at the fiber of my being.", "Though the appointed time had come, I did not attend the event. In fact, I spent " +
            "most of my day lost in thought. It was something I should have done a long time " +
            "ago."));
        yield return lineBreak();
        yield return lineBreak();
        yield return text(@"I had come to a crossroads - a self-reckoning where the distress of existence was laid bare before me. I could continue onward on my path towards my appointed Obsession or I could forge a new path, one galvanized by my own impulses - wild and unfettered. Whichever I chose, I knew then that I would need to see it through to the bitter end.");
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("bold", true))
        {
            yield return text("I chose:");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return link("To keep my Obsession.", "Gen3Token2a", null);
        yield return text(" ");
        using (styleScope("italic", true))
        {
            yield return text("(This option will award you ");
            using (styleScope("bold", true))
            {
                yield return text("4VP");
            }
            yield return text(" ");
            yield return text("for completing your Obsession or cause you to lose ");
            using (styleScope("bold", true))
            {
                yield return text("4VP");
            }
            yield return text(" ");
            yield return text("for leaving it incomplete. You ");
            using (styleScope("bold", true))
            {
                yield return text("must");
            }
            yield return text(" ");
            yield return text("choose this option if your Obsession is already completed.)");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("OR");
