        }
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.question == Vars.cureplayer)
        {
            yield return text(@"The patient is perfectly physically and mentally fit. I find absolutely nothing wrong with such a fine specimen of completely normal human breedstock and am utterly confused as to why they were admitted! Such sharp teeth, such glorious pallor, such divine form; why I wish all patients were so adequately equipped.");
            yield return lineBreak();
            yield return lineBreak();

        }
        else if (Vars.test >= 3)
        {
            yield return text("Alas, despite such a ");
            using (styleScope("bold", true))
            {
                yield return text("healthy");
            }
            yield return text("candidate for mental reformation, I must admit that they are too instrumental in " +
            "the region to be confined to such dismal environs. No, I must satiate myself, an" +
            "d the Asylum, with others who are afflicted ");
            using (styleScope("italic", true))
            {
                yield return text("(and less important)");
            }
            yield return text(". Release has thereby been procured upon certain private matters being addressed." +
            " It is my hope that they will provide a suitable referral in their stead.");
            yield return lineBreak();
            yield return lineBreak();

        }
        else
        {
            yield return text("Uggh. ");
            yield return lineBreak();
            yield return lineBreak();
            yield return text(@"Perhaps it is unprofessional to pen my disgust upon the page, but this patient is completely undesirable for admittance. Or might I say, unfit for our institute's psychological consumption. Still, it is imperative that I negotiate the matter with the to-be-released ");
            yield return text(Vars.question);
            yield return text(@" as I find myself unsatiated by this meager assessment. I am sure a referral to our glorious facility will suffice. Perhaps they know of one who is afflicted by instability - perhaps one well-fed, with rosy cheeks, and warm blood flowing through their veins.");
            yield return lineBreak();
            yield return lineBreak();

        }
        yield return lineBreak();
        yield return lineBreak();
        using (styleScope("hook", "h0000360"))
            yield return link("Click to continue...", null, () => enchantHook("h0000360", HarloweEnchantCommand.Replace, passage360_Fragment_0));
        //if (Vars.round == 19)
