    // #358: AsylumTestResults

    void passage378_Init()
    {
        this.Passages[@"AsylumTestResults"] = new StoryPassage(@"AsylumTestResults", new string[] { "revised", }, passage378_Main);
    }

    IStoryThread passage378_Main()
    {
        using (styleScope("bold", true))
        {
            yield return text("Patient ");
            yield return text(Vars.question);
            yield return text(" ");
            yield return text("- Assessment Results");
        }
        yield return lineBreak();
        yield return lineBreak();
        yield return text("After completion of a full mental evaluation, a basal metabolism test was conduct" +
            "ed, indicating ");
        yield return text(macros1.either("an abnormally low result which could be symptomatic of disease in the endocrine a" +
            "nd nervous system.", "a reasonably low result which is usually accompanied by low blood pressure and ge" +
            "neral malaise.", "no statistically significant variation.", "a slightly higher result which could be dietary in nature.", "an abnormally high percentage of carbon dioxide production sometimes associated w" +
            "ith agitated and aggressive behavior."));
        yield return text(" ");
        yield return text("This was accompanied by a standard physical examination which revealed ");
        yield return text(macros1.either("minor signs of malnutrition, dehydration, and ruddy complexion, usually associate" +
            "d with stressful events.", "a healthy individual within the typical ranges considered as normal.", "nothing particularly concerning or outside of the norm aside from several chemica" +
            "l burn marks across the forearms.", "signs of obesity due to a life of sedentary indulgence common amongst the upper-m" +
            "iddle class."));
        yield return lineBreak();
        yield return lineBreak();
        if (Vars.test <= 3)
        {
            if (Vars.AsylumTestResultsnextpsg == "" || Vars.AsylumTestResultsnextpsg == 0)
            {
                Vars.AsylumTestResultsnextpsg = macros1.either(1, 2, 3, 4, 5);
            }
            Vars.outcome = Vars.AsylumTestResultsnextpsg;
            if (Vars.outcome == 1)
            {
                yield return text("It is of my informed opinion that patient ");
                yield return text(Vars.question);
                yield return text(" should receive continued evaluation over the coming years. This can be achieved b" +
            "y infrequent visitations by a physician. Full release dependent upon ");
                using (styleScope("bold", true))
                {
                    yield return text("payment of $1");
                }
                yield return text(".");
                yield return lineBreak();
                yield return lineBreak();

            }
            if (Vars.outcome == 2)
            {
                yield return text("Patient ");
                yield return text(Vars.question);
                yield return text(" has been admitted for static electro-therapy and is progressing towards full rele" +
            "ase in the coming weeks. Prescribed laudanum and phosphates for nerves. Recommen" +
            "d bed rest and mild sedation. Patient severely disputes this prescriptive inacti" +
            "on.");
                yield return lineBreak();
                yield return lineBreak();

            }
            if (Vars.outcome == 3)
            {
                yield return text("I have offered training to a close associate of patient ");
                yield return text(Vars.question);
                yield return text(@", in order to assist with specified home care upon release. Subject's behavior and mental state is erratic enough to warrant vigilant supervision. While this caretaker's visage suggests that they may also benefit from psychoanalysis, I am satisfied by their dedication and promise to provide the utmost care to ");
                yield return text(Vars.question);
                yield return text(".");
                yield return lineBreak();
                yield return lineBreak();

            }
            if (Vars.outcome == 4)
            {
                yield return text("After several aggressive outbursts while confined, patient ");
                yield return text(Vars.question);
                yield return text(@" has been restrained during the evenings to prevent possible self-harm. I have consulted with members of the Vienna Psychoanalytic Society and their analysis implies deep-seated sexual repression manifesting in dissociative behavior. We are proceeding with an operation to sterilize the patient. This should have the combined effect of reducing a drive towards the destruction of self and others.");
                yield return lineBreak();
                yield return lineBreak();

            }
            if (Vars.outcome == 5)
            {
                yield return text("It appears patient ");
                yield return text(Vars.question);
                yield return text(@" has no physical or noticeable mental deficiencies, though their demeanor is forceful at times. Ailment is assumed to be psychological in nature, possibly brought about by recent stresses. I have recommended heroin for treatment, as it is readily available, non-addictive, and reasonably priced. Perhaps the relaxing effects will also provide respite.");
                yield return lineBreak();
                yield return lineBreak();

            }
        }
        else
        {
            yield return text("Patient ");
